# Auto-regressive generation loop
def generate(prompt, model, tokenizer, max_new=50):
    ids = tokenizer.encode(prompt)
    for _ in range(max_new):
        logits = model(ids)          # shape: [vocab_size]
        next_id = logits.argmax()    # greedy; or sample
        if next_id == tokenizer.eos: break
        ids.append(next_id)
    return tokenizer.decode(ids)
